Here's a complete example of a Discord bot using **Discord.js v14** that includes a **`/ban`** slash command. This bot will allow users with the appropriate permissions to ban a member from the server.

---

### ✅ Prerequisites

Make sure you have:

- Node.js (v16 or higher)
- `discord.js` v14 installed
- A Discord bot token (create one at [https://discord.com/developers/applications](https://discord.com/developers/applications))

---

### 📦 Install Dependencies

```bash
npm init -y
npm install discord.js
```

---

### 📜 `index.js` (Main Bot File)

```js
const { Client, GatewayIntentBits, PermissionsBitField } = require('discord.js');

// Create a new client
const client = new Client({
  intents: [
    GatewayIntentBits.Guilds,
    GatewayIntentBits.GuildMembers,
    GatewayIntentBits.MessageContent,
  ],
});

// Replace with your bot token
const TOKEN = 'YOUR_BOT_TOKEN_HERE';

// Command handler
const commands = [
  {
    name: 'ban',
    description: 'Ban a member from the server.',
    options: [
      {
        name: 'user',
        description: 'The user to ban.',
        type: 6, // User type
        required: true,
      },
      {
        name: 'reason',
        description: 'The reason for the ban.',
        type: 3, // String type
        required: false,
      },
    ],
  },
];

// Register slash commands
client.on('ready', async () => {
  console.log(`Logged in as ${client.user.tag}!`);

  // Register commands in all guilds
  const commandData = commands.map(command => ({
    name: command.name,
    description: command.description,
    options: command.options,
  }));

  const guild = client.guilds.cache.first(); // Or use a specific guild ID
  if (guild) {
    await guild.commands.set(commandData);
    console.log('Slash commands registered.');
  } else {
    console.log('No guild found. Commands will be registered globally.');
    await client.application.commands.set(commandData);
  }
});

// Handle slash command interactions
client.on('interactionCreate', async (interaction) => {
  if (!interaction.isCommand()) return;

  const { commandName, options } = interaction;

  if (commandName === 'ban') {
    const user = options.getUser('user');
    const reason = options.getString('reason') || 'No reason provided';

    // Check if the user has permission to ban
    if (!interaction.memberPermissions.has(PermissionsBitField.Flags.BanMembers)) {
      return interaction.reply({
        content: 'You don\'t have permission to ban members.',
        ephemeral: true,
      });
    }

    // Check if the user is the same as the bot
    if (user.id === client.user.id) {
      return interaction.reply({
        content: 'I can\'t ban myself.',
        ephemeral: true,
      });
    }

    // Check if the user is a bot
    if (user.bot) {
      return interaction.reply({
        content: 'I can\'t ban another bot.',
        ephemeral: true,
      });
    }

    // Ban the user
    try {
      await user.ban({ reason });
      interaction.reply({
        content: `${user} has been banned. Reason: ${reason}`,
        ephemeral: true,
      });
    } catch (error) {
      console.error('Error banning user:', error);
      interaction.reply({
        content: 'I couldn\'t ban that user. Please try again later.',
        ephemeral: true,
      });
    }
  }
});

// Login the bot
client.login(TOKEN);
```

---

### 📌 Notes

- **Permissions**: The bot must have the `Ban Members` permission in the server.
- **Guilds**: The bot can register commands globally or in a specific guild. You can modify the `guild` part to use a specific guild ID.
- **Ephemeral Replies**: All replies are ephemeral (only visible to the user who triggered the command) for privacy and security.

---

### 🚀 Run the Bot

```bash
node index.js
```

