### 🐍 4. Code: `snake.h`

```c
#ifndef SNAKE_H
#define SNAKE_H

#include <SDL2/SDL.h>

typedef struct {
    int x, y;
    int width, height;
    SDL_Texture *texture;
} SnakeSegment;

typedef struct {
    int x, y;
    int width, height;
    SDL_Texture *texture;
} Apple;

typedef struct {
    int x, y;
    int width, height;
    SDL_Texture *texture;
} Background;

typedef struct {
    int length;
    SnakeSegment *segments;
    int dx, dy;
    int score;
} Snake;

void initSnake(Snake *snake, int x, int y);
void updateSnake(Snake *snake, Apple *apple);
void drawSnake(SDL_Renderer *renderer, Snake *snake);
void drawApple(SDL_Renderer *renderer, Apple *apple);
