void handleInput(Snake *snake);
void freeSnake(Snake *snake);

#endif
```

---

### 🧩 5. Code: `main.c`

```c
#include <SDL2/SDL.h>
#include <stdio.h>
#include <stdlib.h>
#include "snake.h"

// Constants
#define SCREEN_WIDTH 800
#define SCREEN_HEIGHT 600
#define SNAKE_SPEED 10
#define TILE_SIZE 20

// Load texture from file
SDL_Texture* loadTexture(const char* path, SDL_Renderer* renderer) {
    SDL_Surface* surface = SDL_LoadBMP(path);
    if (!surface) {
        printf("Failed to load texture: %s\n", SDL_GetError());
        exit(1);
    }
    SDL_Texture* texture = SDL_CreateTextureFromSurface(renderer, surface);
    SDL_FreeSurface(surface);
    return texture;
}

int main(int argc, char* argv[]) {
    SDL_Init(SDL_INIT_VIDEO);
    SDL_Window* window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, SCREEN_WIDTH, SCREEN_HEIGHT, 0);
    SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

    // Load images
    Background background = {0, 0, SCREEN_WIDTH, SCREEN_HEIGHT, loadTexture("images/background.png", renderer)};
    Apple apple = {100, 100, TILE_SIZE, TILE_SIZE, loadTexture("images/apple.png", renderer)};
    Snake snake;
    initSnake(&snake, SCREEN_WIDTH / 2, SCREEN_HEIGHT / 2);

    SDL_Event event;
    int running = 1;
    Uint32 lastTime = 0;

    while (running) {
        Uint32 currentTime = SDL_GetTicks();
        if (currentTime - lastTime > SNAKE_SPEED) {
            lastTime = currentTime;

            // Handle input
            while (SDL_PollEvent(&event)) {
                if (event.type == SDL_QUIT) {
                    running = 0;
                }
                handleInput(&snake);
            }

            // Update game
            updateSnake(&snake, &apple);

            // Draw
            SDL_RenderClear(renderer);
            drawBackground(renderer, &background);
            drawApple(renderer, &apple);
            drawSnake(renderer, &snake);
            SDL_RenderPresent(renderer);
        }
    }

    // Clean up
    freeSnake(&snake);
    SDL_DestroyTexture(background.texture);
    SDL_DestroyTexture(apple.texture);
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();

    return 0;
}
```

---

### 🧱 6. Code: `snake.c`

```c
#include "snake.h"
#include <stdio.h>
#include <stdlib.h>

void initSnake(Snake *snake, int x, int y) {
    snake->length = 1;
    snake->segments = (SnakeSegment*)malloc(sizeof(SnakeSegment));
    snake->segments[0].x = x;
    snake->segments[0].y = y;
    snake->segments[0].width = TILE_SIZE;
    snake->segments[0].height = TILE_SIZE;
    snake->dx = 0;
    snake->dy = 0;
    snake->score = 0;
}

void freeSnake(Snake *snake) {
    free(snake->segments);
}

void handleInput(Snake *snake) {
    SDL_Event event;
    while (SDL_PollEvent(&event)) {
        if (event.type == SDL_KEYDOWN) {
            switch (event.key.keysym.sym) {
                case SDLK_UP:
                    if (snake->dy != 1) {
                        snake->dx = 0;
                        snake->dy = -1;
                    }
                    break;
                case SDLK_DOWN:
                    if (snake->dy != -1) {
                        snake->dx = 0;
                        snake->dy = 1;
                    }
                    break;
                case SDLK_LEFT:
                    if (snake->dx != 1) {
                        snake->dx = -1;
                        snake->dy = 0;
                    }
                    break;
                case SDLK_RIGHT:
                    if (snake->dx != -1) {
                        snake->dx = 1;
                        snake->dy = 0;
                    }
                    break;
                case SDLK_ESCAPE:
                    exit(0);
            }
        }
    }
}

void updateSnake(Snake *snake, Apple *apple) {
    // Move the snake
    for (int i = snake->length - 1; i > 0; i--) {
        snake->segments[i].x = snake->segments[i - 1].x;
        snake->segments[i].y = snake->segments[i - 1].y;
    }

    snake->segments[0].x += snake->dx * TILE_SIZE;
    snake->segments[0].y += snake->dy * TILE_SIZE;

    // Check collision with walls
    if (snake->segments[0].x < 0 || snake->segments[0].x >= SCREEN_WIDTH ||
        snake->segments[0].y < 0 || snake->segments[0].y >= SCREEN_HEIGHT) {
        exit(0);
    }

    // Check collision with self
    for (int i = 1; i < snake->length; i++) {
        if (snake->segments[0].x == snake->segments[i].x &&
            snake->segments[0].y == snake->segments[i].y) {
            exit(0);
        }
    }

    // Check collision with apple
    if (snake->segments[0].x == apple->x && snake->segments[0].y == apple->y) {
        snake->length++;
        snake->score++;
        // Generate new apple
        apple->x = rand() % (SCREEN_WIDTH / TILE_SIZE) * TILE_SIZE;
        apple->y = rand() % (SCREEN_HEIGHT / TILE_SIZE) * TILE_SIZE;
    }
}

void drawSnake(SDL_Renderer *renderer, Snake *snake) {
    for (int i = 0; i < snake->length; i++) {
        SDL_Rect rect = {snake->segments[i].x, snake->segments[i].y, snake->segments[i].width, snake->segments[i].height};
        SDL_RenderCopy(renderer, snake->segments[i].texture, NULL, &rect);
    }
}

void drawApple(SDL_Renderer *renderer, Apple *apple) {
    SDL_Rect rect = {apple->x, apple->y, apple->width, apple->height};
    SDL_RenderCopy(renderer, apple->texture, NULL, &rect);
}

void drawBackground(SDL_Renderer *renderer, Background *background) {
    SDL_Rect rect = {background->x, background->y, background->width, background->height};
    SDL_RenderCopy(renderer, background->texture, NULL, &rect);
}
```

